import React from 'react';
import Svg, { Path } from 'react-native-svg';

interface Props {
  size?: number;
  color?: string;
  strokeWidth?: number;
}

/** SF-style `chevron.forward` — cart checkout thumb (Figma 1:234, 28×28 @ baseline). */
export function ChevronForwardIcon({
  size = 28,
  color = '#FFFFFF',
  strokeWidth = 2.5,
}: Props) {
  return (
    <Svg width={size} height={size} viewBox="0 0 28 28">
      <Path
        d="M 11 9 L 17 14 L 11 19"
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </Svg>
  );
}

/**
 * Swipe-to-confirm checkout control (Figma Cart 1:229 “Checkout Slide”).
 *
 * Track: Rectangle 28 (1:230) — 174×44 @390, `RADIUS.md`, inset fill.
 * Thumb: Rectangle 29 (1:233) — gradient + 1px white border + chevron (1:234);
 *   slightly taller than the track so it sits proud (46 vs 44 @ baseline).
 */
import React, { useCallback, useMemo } from 'react';
import { StyleSheet, Text, View, useWindowDimensions } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  runOnJS,
  interpolate,
  Extrapolation,
} from 'react-native-reanimated';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';
import { LinearGradient } from 'expo-linear-gradient';
import {
  COLORS,
  CHECKOUT_THUMB_CHEVRON_PT,
  CHECKOUT_THUMB_GRADIENT_ANGLE_DEG,
  CHECKOUT_THUMB_SIZE_PT,
  CHECKOUT_TRACK_HEIGHT_PT,
  CHECKOUT_TRACK_WIDTH_PT,
  FONT,
  GRADIENTS,
  RADIUS,
} from '../constants/theme';
import { ChevronForwardIcon } from './icons/ChevronForwardIcon';

interface CheckoutSliderProps {
  onConfirm?: () => void;
}

const DESIGN_BASELINE = 390;
/** “Checkout” text x (175) − slide frame x (108) in Figma — label area inset from frame left. */
const CHECKOUT_LABEL_LEFT_PT = 67;

/** CSS-style linear-gradient angle (0° = up, clockwise) → `expo-linear-gradient` start/end in unit space. */
function cssLinearGradientToUnitPoints(angleDeg: number) {
  const a = ((90 - angleDeg) * Math.PI) / 180;
  return {
    start: { x: 0.5 - 0.5 * Math.cos(a), y: 0.5 + 0.5 * Math.sin(a) } as const,
    end:   { x: 0.5 + 0.5 * Math.cos(a), y: 0.5 - 0.5 * Math.sin(a) } as const,
  };
}

export function CheckoutSlider({ onConfirm }: CheckoutSliderProps) {
  const { width } = useWindowDimensions();
  const scale = width / DESIGN_BASELINE;
  const TRACK_WIDTH = Math.min(CHECKOUT_TRACK_WIDTH_PT * scale, width - 40);
  const scaledTrackH = CHECKOUT_TRACK_HEIGHT_PT * scale;
  const scaledThumb = CHECKOUT_THUMB_SIZE_PT * scale;
  const scaledChevron = CHECKOUT_THUMB_CHEVRON_PT * scale;
  const slotH = scaledThumb;
  const trackTop = (scaledThumb - scaledTrackH) / 2;
  const r = RADIUS.md * scale;
  const thumbBorderW = scale;
  const thumbInnerR = Math.max(0, r - thumbBorderW);

  const MAX_DRAG = TRACK_WIDTH - scaledThumb;

  const translateX = useSharedValue(0);

  const gradEnds = useMemo(
    () => cssLinearGradientToUnitPoints(CHECKOUT_THUMB_GRADIENT_ANGLE_DEG),
    [],
  );

  const confirm = useCallback(() => {
    onConfirm?.();
  }, [onConfirm]);

  const pan = Gesture.Pan()
    .onChange((e) => {
      'worklet';
      translateX.value = Math.max(0, Math.min(e.translationX, MAX_DRAG));
    })
    .onEnd(() => {
      'worklet';
      if (translateX.value >= MAX_DRAG * 0.7) {
        translateX.value = withSpring(MAX_DRAG, { damping: 18, stiffness: 120 }, () => {
          runOnJS(confirm)();
        });
      } else {
        translateX.value = withSpring(0, { damping: 18, stiffness: 120 });
      }
    });

  const thumbStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: translateX.value }],
  }));

  const labelOpacity = useAnimatedStyle(() => ({
    opacity: interpolate(
      translateX.value,
      [0, MAX_DRAG * 0.5],
      [1, 0],
      Extrapolation.CLAMP,
    ),
    transform: [
      {
        translateX: interpolate(
          translateX.value,
          [0, MAX_DRAG],
          [0, 12 * scale],
          Extrapolation.CLAMP,
        ),
      },
    ],
  }));

  const doneOpacity = useAnimatedStyle(() => ({
    opacity: interpolate(
      translateX.value,
      [MAX_DRAG * 0.5, MAX_DRAG],
      [0, 1],
      Extrapolation.CLAMP,
    ),
  }));

  return (
    <View style={[styles.slideFrame, { width: TRACK_WIDTH, height: slotH }]}>
      <View
        style={[
          styles.track,
          {
            top:            trackTop,
            height:         scaledTrackH,
            width:          TRACK_WIDTH,
            borderRadius:   r,
          },
        ]}
      >
        <View
          style={[styles.labelSlot, { left: CHECKOUT_LABEL_LEFT_PT * scale, right: 14 * scale }]}
          pointerEvents="none"
        >
          <Animated.Text style={[styles.checkoutLabel, { lineHeight: scaledTrackH }, labelOpacity]}>
            Checkout
          </Animated.Text>
          <Animated.Text style={[styles.doneLabel, { lineHeight: scaledTrackH }, doneOpacity]}>
            Done! ✓
          </Animated.Text>
        </View>
      </View>

      <GestureDetector gesture={pan}>
        <Animated.View
          style={[
            styles.thumbOuter,
            {
              width:          scaledThumb,
              height:         scaledThumb,
              top:            0,
              left:           0,
              borderRadius:   r,
              borderWidth:    thumbBorderW,
            },
            thumbStyle,
          ]}
        >
          <LinearGradient
            colors={[...GRADIENTS.accent]}
            locations={[0.017011, 1]}
            start={gradEnds.start}
            end={gradEnds.end}
            style={[StyleSheet.absoluteFill, { borderRadius: thumbInnerR }]}
          />
          <View style={styles.thumbIconCenter} pointerEvents="none">
            <ChevronForwardIcon
              size={scaledChevron}
              strokeWidth={Math.max(2, 2.5 * scale)}
            />
          </View>
        </Animated.View>
      </GestureDetector>
    </View>
  );
}

